  private skipSpaces() {
    while (this.pos < this.input.length && /\s/.test(this.input[this.pos])) {
      this.pos++;
    }
  }
  private peek() {
    this.skipSpaces();
    if (this.pos < this.input.length) {
      return this.input[this.pos];
    }
    return null;
  }
  private consume(expected?: string) {
    this.skipSpaces();
    const ch = this.input[this.pos];
    if (expected && ch !== expected) {
      throw new Error(`Expected '${expected}' but got '${ch}' at position ${this.pos}`);
    }
    this.pos++;
    return ch;
  }
  private isEnd() {
    this.skipSpaces();
    return this.pos >= this.input.length;
  }
  // parse expression: add/sub
  parseExpression(): number {
    let left = this.parseTerm();
    while (true) {
      this.skipSpaces();
      if (this.pos < this.input.length && (this.input[this.pos] === '+' || this.input[this.pos] === '-')) {
        const op = this.input[this.pos];
        this.pos++;
        const right = this.parseTerm();
        if (op === '+') left = left + right;
        else left = left - right;
      } else {
        break;
      }
    }
    return left;
  }
  // parse term: mul/div
  parseTerm(): number {
    let left = this.parseFactor();
    while (true) {
      this.skipSpaces();
      if (this.pos < this.input.length && (this.input[this.pos] === '*' || this.input[this.pos] === '/')) {
        const op = this.input[this.pos];
        this.pos++;
