    return left;
  }
  // parse factor: unary +/-
  parseFactor(): number {
    this.skipSpaces();
    if (this.pos < this.input.length && (this.input[this.pos] === '+' || this.input[this.pos] === '-')) {
      const sign = this.input[this.pos] === '+' ? 1 : -1;
