  // parse primary: number or parentheses
  parsePrimary(): number {
    this.skipSpaces();
    const ch = this.input[this.pos];
    if (ch === '(') {
      this.consume('(');
      const value = this.parseExpression();
      this.consume(')');
      return value;
    } else if (/\d/.test(ch)) {
      // parse number
